#!/usr/bin/env node
/**
 * GitHub Clone Fixture Script
 * 
 * Clones a test repository for use in integration tests.
 * Run once before running tests that need the repo.
 * 
 * Usage: node engine/tests/fixtures/github/clone-repo.mjs
 */

import { writeFileSync, mkdirSync, existsSync, readFileSync } from 'fs';
import { join } from 'path';

// Configuration
const REPO_OWNER = 'RSBalchII';
const REPO_NAME = 'anchor-engine-node';
const OUTPUT_PATH = 'engine/tests/fixtures/github/RSBalchII';
const API_BASE = process.env.API_URL || 'http://localhost:3160';

console.log('🚀 GitHub Clone Fixture');
console.log('======================');
console.log(`Repository: ${REPO_OWNER}/${REPO_NAME}`);
console.log(`Output path: ${OUTPUT_PATH}`);
console.log(`API URL: ${API_BASE}`);

// Ensure output directory exists
if (!existsSync(OUTPUT_PATH)) {
  mkdirSync(OUTPUT_PATH, { recursive: true });
  console.log(`\n✅ Created output directory: ${OUTPUT_PATH}`);
}

// Check if engine is running
async function isEngineRunning() {
  try {
    const response = await fetch(`${API_BASE}/health`);
    return response.ok;
  } catch {
    console.log('\n⚠️  Engine not running. Starting engine...');

    // Try to start the engine
    const { spawn } = await import('child_process');
    const server = spawn('pnpm', ['start'], {
      cwd: process.cwd(),
      stdio: 'pipe',
      shell: true
    });

    let serverReady = false;
    server.stdout.on('data', (data) => {
      const log = data.toString().trim();
      if (log.includes('listening') || log.includes('ready')) {
        serverReady = true;
        console.log(`✅ Engine started and ready: ${log}`);
      }
    });

    // Wait up to 60 seconds for engine to start
    await new Promise((resolve) => {
      const timeout = setTimeout(() => {
        server.kill();
        resolve();
      }, 60000);

      const interval = setInterval(() => {
        if (serverReady) {
          clearInterval(interval);
          clearTimeout(timeout);
          resolve();
        }
      }, 1000);
    });

    if (!serverReady) {
      server.kill();
      throw new Error('Engine failed to start within 60 seconds. Check your PATH and ensure pnpm is installed.');
    }

    return true;
  }
}

// Clone the repository via API
async function cloneRepository() {
  try {
    const response = await fetch(`${API_BASE}/memory/github/clone`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        owner: REPO_OWNER,
        repo: REPO_NAME,
        output_dir: 'RSBalchII',
        depth: 0,
      }),
    });

    const result = await response.json();

    if (result.success) {
      console.log('\n✅ Clone successful!');
      console.log(`   Output directory: ${join(process.cwd(), 'engine/tests/fixtures/github')}`);

      // List files in cloned repo
      const { readdirSync } = await import('fs');
      const files = readdirSync(OUTPUT_PATH, { recursive: true });
      console.log(`   Total items: ${files.length}`);
      console.log('   Files:', files.slice(0, 20).join(', '));

      // Save success marker
      writeFileSync(
        join(OUTPUT_PATH, 'clone-success.json'),
        JSON.stringify(result, null, 2)
      );

      return true;
    } else {
