      const timeout = setTimeout(() => {
        server.kill();
        resolve();
      }, 60000);

      const interval = setInterval(() => {
        if (serverReady) {
          clearInterval(interval);
          clearTimeout(timeout);
          resolve();
        }
      }, 1000);
    });

    if (!serverReady) {
      server.kill();
      throw new Error('Engine failed to start within 60 seconds. Check your PATH and ensure pnpm is installed.');
